<template>
    <div style="border: 1px solid">
        <slot></slot><!-- 不带name则默认渲染innerHTML（具名插槽除外） -->
        <el-divider></el-divider>
        <slot name="content"></slot>
        <el-divider></el-divider>
        <slot name="user" :username="username" :password="password"></slot><!--允许外部调用内部组件的值,类似于slot-scope-->
    </div>
</template>
<script>
    export default {
        data() {
            return {
                username: '张三',
                password: '李四'
            }
        }
    }
</script>
