<template>
    <el-row type="flex" justify="space-between" :gutter="12">
        <el-col>
            <el-select :value="data.provinceId || null" class="w-100" @change="e=>$emit('a', {...data, provinceId: e, cityId: '', areaId: ''})" clearable filterable>
                <el-option v-for="i in provinces" :key="i.id" :value="i.id" :label="i.name"></el-option>
            </el-select>
        </el-col>
        <el-col>
            <el-select :value="data.cityId || null" class="w-100" @change="e=>$emit('a', {...data, cityId: e, areaId: ''})" clearable filterable>
                <el-option v-for="i in cities" :key="i.id" :value="i.id" :label="i.name"></el-option>
            </el-select>
        </el-col>
        <el-col>
            <el-select :value="data.areaId || null" class="w-100" @change="e=>$emit('a', {...data, areaId: e})" clearable filterable>
                <el-option v-for="i in areas" :key="i.id" :value="i.id" :label="i.name"></el-option>
            </el-select>
        </el-col>
    </el-row>
</template>
<script>

    // 地区信息，一般从后端获取
    import regions from "@/assets/json/regions.json"

    export default {
        props: {
            data: {
                type: Object,
                required: true,
            }
        },
        data() {
            return {
                regions: regions
            }
        },
        model: {
            prop: 'data',
            event: 'a'
        },
        computed: {
            provinces() {
                return this.regions.filter(e => e.parentId === 0);
            },
            cities() {
                return this.regions.filter(e => e.parentId === this.data.provinceId);
            },
            areas() {
                return this.regions.filter(e => e.parentId === this.data.cityId);
            }
        }
    }
</script>
